create table if not exists public.integration_health_snapshots(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id)on delete cascade,summary jsonb not null,providers jsonb not null,queues jsonb not null,runtime jsonb not null,snapshot_hash text not null check(snapshot_hash~'^[a-f0-9]{64}$'),created_by uuid not null references public.profiles(id),created_at timestamptz not null default now(),unique(organization_id,snapshot_hash));create index if not exists integration_health_snapshots_org_idx on public.integration_health_snapshots(organization_id,created_at desc);alter table public.integration_health_snapshots enable row level security;create policy integration_health_director_read on public.integration_health_snapshots for select to authenticated using(organization_id=(select public.current_organization_id())and exists(select 1 from public.profiles p where p.id=auth.uid()and coalesce(p.commercial_role,case when p.role='admin'then'director'else p.role end)='director'));revoke all on public.integration_health_snapshots from anon,authenticated;grant select on public.integration_health_snapshots to authenticated;
